#include <stdio.h>
#include <math.h>
#define N 2000000
#define SQRT3 1.73205080757

double f(double y, double a, double r1, double r2, double r3) {
    double L = -(a - y / SQRT3);
    double R = a - y / SQRT3;
    if (fabs(y) > r1) return 0.0;
    double dx1 = sqrt(max(0.0, r1 * r1 - y * y));
    L = max(L, -dx1);
    R = min(R, dx1);
    double y2 = a * SQRT3 / 2.0;
    if (fabs(y - y2) > r2) return 0.0;
    double dx2 = sqrt(max(0.0, r2 * r2 - (y - y2) * (y - y2)));
    L = max(L, a / 2.0 - dx2);
    R = min(R, a / 2.0 + dx2);
    double y3 = a * SQRT3 / 2.0;
    if (fabs(y - y3) > r3) return 0.0;
    double dx3 = sqrt(max(0.0, r3 * r3 - (y - y3) * (y - y3)));
    L = max(L, -a / 2.0 - dx3);
    R = min(R, -a / 2.0 + dx3);
    return max(0.0, R - L);
}

void solve() {
    double a, r1, r2, r3;
    scanf("%lf %lf %lf %lf", &a, &r1, &r2, &r3);
    double H = a * SQRT3;
    double h = H / N;
    double sum = f(0, a, r1, r2, r3) + f(H, a, r1, r2, r3);
    for (int i = 1; i < N; i += 2) {
        sum += 4.0 * f(i * h, a, r1, r2, r3);
    }
    for (int i = 2; i < N; i += 2) {
        sum += 2.0 * f(i * h, a, r1, r2, r3);
    }
    double area = sum * h / 3.0;
    printf("%.7f\n", area);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        solve();
    }
    return 0;
}

